#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

struct Node{
    int lh,rh,sh;
    int sum,tag;
}t[N<<2];

int n,m;

void build(int cur,int l,int r){
    t[cur]={0,0,0,r-l+1,-1};
    if(l==r)
        return;
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
}

void push_down(int cur,int l,int r){
    int mid=l+r>>1;
    if(t[cur].tag==0){
        t[cur*2]={mid-l+1,mid-l+1,mid-l+1,0,0};
        t[cur*2+1]={r-mid,r-mid,r-mid,0,0};
    }else if(t[cur].tag==1){
        t[cur*2]={0,0,0,mid-l+1,1};
        t[cur*2+1]={0,0,0,r-mid,1};
    }
    t[cur].tag=-1;
}

void Dig(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y){
        t[cur]={r-l+1,r-l+1,r-l+1,0,0};
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        Dig(cur*2,l,mid,x,y);
    if(y>mid)
        Dig(cur*2+1,mid+1,r,x,y);
    t[cur].lh=(t[cur*2].sum?t[cur*2].lh:t[cur*2].lh+t[cur*2+1].lh);
    t[cur].rh=(t[cur*2+1].sum?t[cur*2+1].rh:t[cur*2+1].rh+t[cur*2].rh);
    t[cur].sh=max(max(t[cur*2].sh,t[cur*2+1].sh),t[cur*2].rh+t[cur*2+1].lh);
    t[cur].sum=t[cur*2].sum+t[cur*2+1].sum;
}

void Full(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y){
        t[cur]={0,0,0,r-l+1,1};
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        Full(cur*2,l,mid,x,y);
    if(y>mid)
        Full(cur*2+1,mid+1,r,x,y);
    t[cur].lh=(t[cur*2].sum?t[cur*2].lh:t[cur*2].lh+t[cur*2+1].lh);
    t[cur].rh=(t[cur*2+1].sum?t[cur*2+1].rh:t[cur*2+1].rh+t[cur*2].rh);
    t[cur].sh=max(max(t[cur*2].sh,t[cur*2+1].sh),t[cur*2].rh+t[cur*2+1].lh);
    t[cur].sum=t[cur*2].sum+t[cur*2+1].sum;
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(y<=mid)
        return query(cur*2,l,mid,x,y);
    else if(x>mid)
        return query(cur*2+1,mid+1,r,x,y);
    else{
        Node a=query(cur*2,l,mid,x,y),b=query(cur*2+1,mid+1,r,x,y),res;
        res.lh=(a.sum?a.lh:a.lh+b.lh);
        res.rh=(b.sum?b.rh:b.rh+a.rh);
        res.sh=max(max(a.sh,b.sh),a.rh+b.lh);
        res.sum=a.sum+b.sum;
        return res;
    }
}

int main(){
    scanf("%d%d",&n,&m);
    build(1,1,n);
    while(m--){
        int op,l,r;
        scanf("%d%d%d",&op,&l,&r);
        if(op==0)
            Dig(1,1,n,l,r);
        else if(op==1){
            int x,y,len=query(1,1,n,l,r).sum;
            scanf("%d%d",&x,&y);
            if(!len)
                continue;
            Dig(1,1,n,l,r);
            int le=x,ri=y;
            while(le<ri){
                int mid=le+ri+1>>1;
                if(query(1,1,n,x,mid).sum+len>=mid-x+1)
                    le=mid;
                else
                    ri=mid-1;
            }
            Full(1,1,n,x,ri);
        }else
            printf("%d\n",query(1,1,n,l,r).sh);
    }
    return 0;
}
